import React from 'react';
import {BrowserRouter, Route, Switch, Link, NavLink, useParams} from 'react-router-dom';
import './Footer.css'

function Footer() {
  var infoDict = [];
  infoDict['상호'] = '(주)무빗';
  infoDict['대표자명'] = '김창현';
  infoDict['사업자등록번호'] = '000-00-00000';
  infoDict['연락처'] = '00-000-0000';
  infoDict['팩스'] = '000-0000-0000';
  
  const lis = [];
  for (var key in infoDict) {
    let i = 0;
    lis.push(<li key = {i}>{key}: {infoDict[key]}</li>);
  }
  
  return (
    <footer>
      <ul>
      {lis}
      </ul>
    </footer>
  );
}

export default Footer;