import React, { useState } from 'react';
import ReactDOM from 'react-dom';
import {BrowserRouter, Route, Switch, Link, NavLink, useParams} from 'react-router-dom';

import Header from './Header';
import Footer from './Footer';

import './index.css';
import './Login.css';

const Login = ({}) => {
  const [PWType, setPWType] = useState({
    type: 'password',
    visible: false
  });

  const handlePWType = e => {
    setPWType(() => {
      if (!PWType.visible) {
        return { type: 'text', visible: true };
      }
      return { type: 'password', visible: false };
    })
  }

  return ( 
    <div id='login'>
      <form>
        <div class='horizon'>
          <h1>로그인 </h1>
          
        </div>
        <input type="text" name="input_ID" required="true" autofocus="" placeholder="이메일 주소 또는 전화번호" />
        <input type={PWType} name="input_PW" required="true" placeholder="비밀번호" />
        <span onClick={handlePWType}> { PWType.visible ? <span>숨기기</span> : <span>보이기</span> } </span> 
        <input type="submit" class="btn btn--pink" value="로그인" />
        <p><NavLink exact to="/Find">비밀번호를 잊어버리셨나요?</NavLink></p>
      </form>
    </div>
  );
}

export default Login;

