import React from 'react';
import ReactDOM from 'react-dom';
import {BrowserRouter, Route, Switch, Link, NavLink, useParams} from 'react-router-dom';

import Header from './Header';
import Footer from './Footer';
import Banner from './Banner'; 
import Login from './Login';

import './style.css';
import './index.css';

function Intro() {
  var IntroDict = [
    {
      id: 1,
      text: '각종 영화, 시리즈, 실시간 음악방송, 무제한으로 즐겨요!',
      image: 'img/entertainment_set.png'
    },
    {
      id: 2,
      text: '무빗에서만 즐길 수 있는 컨텐츠가, 매주 100편 이상 준비됩니다',
      image: 'img/present_jibun_gohoubi_woman.png'
    },
    {
      id: 3,
      text: '최대 Ultra HD 4K 해상도로, 생생한 감동을 느낄 수 있어요',
      image: 'img/3d_eiga_glass.png'
    },
    {
      id: 4,
      text: '좋아하는 아티스트와의 폰서트를 즐길 수 있어요',
      image: 'img/animal_music_band.png'
    },
    {
      id: 5,
      text: '몰입감을 높이는 우리말 더빙을 들을 수 있어요',
      image: 'img/job_seiyu_ikebo.png'
    },
    {
      id: 6,
      text: '이용권 하나로 여러명과 즐거움을 나눌 수 있어요',
      image: 'img/group_young_world.png'
    }
  ]

  var lis = [];

  for (let i = 0; i < IntroDict.length; i++) {
    lis.push(<Box text={IntroDict[i]['text']} image={IntroDict[i]['image']}/>)
  }

  return (
    <div id="intro">
      {lis}
    </div>  
  );
}
  
  function Box(props) {
    return (
      <div class="box">
        <h2>{props.text}</h2> 
        <img src={props.image}></img>
      </div>
    ); 
  }

function App(){
    return (
        <div>
            <Header />
            <Switch>
                <Route exact path="/"><Banner /><Intro /></Route>
                <Route path="/Login"><Login /></Route>
                <Route path="*">Not found</Route>
            </Switch>
            <Footer /> 
        </div>
    )
}

ReactDOM.render(<BrowserRouter><App /></BrowserRouter>, document.getElementById('root'));

